import type { Mark } from './types';

const PLACEMENT_CAP = 50_000;

/**
 * solveLine — for one line (row or column), enumerate all valid placements
 * of the clues consistent with the current partial state, then for each cell
 * report 'fill' if every placement fills it, 'cross' if every placement leaves
 * it empty, else 'unmarked'.
 *
 * Algorithm: Batenburg & Kosters 2009, "Solving Nonograms by combining relaxations".
 * Time: bounded by PLACEMENT_CAP × N. Space: O(N).
 */
export function solveLine(clues: number[], line: ReadonlyArray<Mark>): Mark[] {
  const N = line.length;
  const out: Mark[] = new Array(N).fill('unmarked');

  if (clues.length === 1 && clues[0] === 0) {
    for (let i = 0; i < N; i++) out[i] = 'cross';
    return out;
  }

  const k = clues.length;
  const minLen = clues.reduce((s, c) => s + c, 0) + (k - 1);
  if (minLen > N) return out;  // contradiction; caller handles

  const everFilled: boolean[] = new Array(N).fill(false);
  const everEmpty:  boolean[] = new Array(N).fill(false);
  let count = 0;
  let exceeded = false;

  // Precompute remaining min space for each clue suffix
  const remainingMin: number[] = new Array(k).fill(0);
  for (let i = k - 1; i >= 0; i--) {
    remainingMin[i] = (clues[i] ?? 0) + (i < k - 1 ? 1 + (remainingMin[i + 1] ?? 0) : 0);
  }

  function recurse(clueIdx: number, start: number, fills: boolean[]) {
    if (exceeded) return;
    if (count >= PLACEMENT_CAP) { exceeded = true; return; }

    if (clueIdx === k) {
      // Validate against current line state
      for (let i = 0; i < N; i++) {
        if (line[i] === 'fill' && !fills[i]) return;
        if (line[i] === 'cross' && fills[i]) return;
      }
      count++;
      for (let i = 0; i < N; i++) {
        if (fills[i]) everFilled[i] = true;
        else          everEmpty[i]  = true;
      }
      return;
    }

    const len = clues[clueIdx]!;
    // Max start position: must leave room for all remaining clues
    const spaceForRemaining = clueIdx < k - 1 ? 1 + (remainingMin[clueIdx + 1] ?? 0) : 0;
    const maxStart = N - len - spaceForRemaining;

    for (let s = start; s <= maxStart; s++) {
      // Check: every cell in [s, s+len) must NOT be 'cross'
      let ok = true;
      for (let i = s; i < s + len; i++) {
        if (line[i] === 'cross') { ok = false; break; }
      }
      if (!ok) continue;

      // Check: the cell right before the run must NOT be 'fill' (would extend the run)
      if (s > 0 && fills[s - 1] === true) continue;
      // After this check, we also need to ensure cell at s+len is not 'fill'
      if (s + len < N && line[s + len] === 'fill') continue;

      // Place
      for (let i = s; i < s + len; i++) fills[i] = true;
      recurse(clueIdx + 1, s + len + 1, fills);
      for (let i = s; i < s + len; i++) fills[i] = false;

      if (exceeded) return;
    }
  }

  const fillsBuf: boolean[] = new Array(N).fill(false);
  recurse(0, 0, fillsBuf);

  if (exceeded || count === 0) return out;

  for (let i = 0; i < N; i++) {
    if (everFilled[i] && !everEmpty[i]) out[i] = 'fill';
    else if (everEmpty[i] && !everFilled[i]) out[i] = 'cross';
  }
  return out;
}
