import { useEffect, useRef } from 'react';
import { TECHNIQUE_NAMES, TECHNIQUE_DESCRIPTIONS, TECHNIQUE_SVGS } from './techniques';

const KEYS = ['completed-clue', 'forced-edge', 'overlap', 'completed-clue-elim', 'multi-line'] as const;

export function GlossaryModal({ initial, onClose }: { initial: string; onClose: () => void }) {
  const sheetRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') onClose(); }
    window.addEventListener('keydown', onKey);
    setTimeout(() => {
      document.getElementById(`tech-${initial}`)?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }, 50);
    return () => window.removeEventListener('keydown', onKey);
  }, [initial, onClose]);

  return (
    <div
      className="etch-glossary-backdrop"
      role="dialog"
      aria-modal="true"
      aria-label="Technique glossary"
      onClick={onClose}
    >
      <div
        className="etch-glossary-sheet"
        ref={sheetRef}
        onClick={e => e.stopPropagation()}
      >
        <header>
          <h2>Techniques</h2>
          <button onClick={onClose} aria-label="Close glossary">×</button>
        </header>
        <ul>
          {KEYS.map(k => (
            <li key={k} id={`tech-${k}`} className={k === initial ? 'highlighted' : ''}>
              <h3>{TECHNIQUE_NAMES[k] ?? k}</h3>
              <div
                className="etch-tech-svg"
                aria-hidden="true"
                dangerouslySetInnerHTML={{ __html: TECHNIQUE_SVGS[k] ?? '' }}
              />
              <p>{TECHNIQUE_DESCRIPTIONS[k]}</p>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}
