const KEY = 'bilko_etch_streak_v1';
const VERSION = 1;

export interface StreakBlob {
  v: 1;
  current: number;
  longest: number;
  freezes: number;
  lastWinDate: string | null;
  completed: string[];
}

const empty: StreakBlob = { v: 1, current: 0, longest: 0, freezes: 0, lastWinDate: null, completed: [] };

function read(): StreakBlob {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return { ...empty };
    const j = JSON.parse(raw);
    if (j.v !== VERSION) return { ...empty };
    return j as StreakBlob;
  } catch { return { ...empty }; }
}

function write(b: StreakBlob) {
  try { localStorage.setItem(KEY, JSON.stringify(b)); } catch {}
}

function daysBetween(a: string, b: string): number {
  return Math.round((Date.parse(b + 'T12:00:00') - Date.parse(a + 'T12:00:00')) / 86_400_000);
}

export function recordDailyWin(iso: string): StreakBlob {
  const cur = read();
  if (cur.completed.includes(iso)) return cur;
  let next: StreakBlob = { ...cur, completed: [...cur.completed, iso].sort() };
  if (cur.lastWinDate) {
    const gap = daysBetween(cur.lastWinDate, iso);
    if (gap === 1) {
      next.current = cur.current + 1;
    } else if (gap > 1) {
      const missed = gap - 1;
      const used = Math.min(missed, cur.freezes);
      next.freezes = cur.freezes - used;
      if (used >= missed) next.current = cur.current + 1;
      else next.current = 1;
    }
    // gap === 0 means same day, already handled by the includes check
  } else {
    next.current = 1;
  }
  // Earn freeze every 7 wins, cap 3
  if (next.completed.length % 7 === 0 && next.freezes < 3) next.freezes += 1;
  next.longest = Math.max(cur.longest, next.current);
  next.lastWinDate = iso;
  write(next);
  return next;
}

export function getStreak(): StreakBlob {
  return read();
}
