import { useEffect, useState } from 'react';

interface Particle {
  id: number;
  x0: number;
  y0: number;
  vx: number;
  vy: number;
  size: number;
  color: string;
}

const N = 30;
const COLORS = ['var(--ink)', '#888888', '#aaaaaa', '#cccccc', '#555555'];

function makeParticles(): Particle[] {
  const cx = 50, cy = 40;
  return Array.from({ length: N }, (_, i) => {
    const angle = (i / N) * Math.PI * 2 + (Math.random() - 0.5) * 0.5;
    const speed = 8 + Math.random() * 12;
    return {
      id: i,
      x0: cx, y0: cy,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed * 0.6,
      size: 4 + Math.random() * 4,
      color: COLORS[i % COLORS.length]!,
    };
  });
}

export function Confetti({ onDone }: { onDone: () => void }) {
  const [particles, setParticles] = useState<Particle[]>([]);

  useEffect(() => {
    const m = matchMedia('(prefers-reduced-motion: reduce)');
    if (m.matches) { onDone(); return; }
    setParticles(makeParticles());
    const t = setTimeout(onDone, 720);
    return () => clearTimeout(t);
  }, [onDone]);

  if (particles.length === 0) return null;

  return (
    <div className="etch-confetti" aria-hidden="true">
      {particles.map(p => (
        <span
          key={p.id}
          style={{
            left: `${p.x0}vw`,
            top: `${p.y0}vh`,
            width: p.size,
            height: p.size,
            background: p.color,
            '--vx': p.vx,
            '--vy': p.vy,
          } as React.CSSProperties & { '--vx': number; '--vy': number }}
        />
      ))}
    </div>
  );
}
