import { useGameState, useGameActions } from '../state/store';

function fmt(ms: number): string {
  const total = Math.floor(ms / 1000);
  const m = Math.floor(total / 60), s = total % 60;
  return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

export function HudSlot() {
  const s = useGameState();
  const a = useGameActions();
  const { board } = s;
  if (board.cells.length === 0) return null;
  return (
    <div className="etch-hud" data-slot="hud">
      <span className="hud-pill">{s.size}</span>
      <span className="hud-timer" aria-live="off">{fmt(s.timeMs)}</span>
      {s.canUndo && (
        <button className="hud-btn" onClick={() => a.undo()} aria-label="Undo">↩</button>
      )}
      <button className="hud-btn" onClick={() => a.restart()} aria-label="Restart">↺</button>
      <button
        className="hud-btn"
        onClick={() => a.togglePrimary()}
        aria-label={`Mode: ${s.primary}`}
        aria-pressed={s.primary === 'cross'}
      >
        {s.primary === 'fill' ? '■ Fill' : '× Cross'}
      </button>
      {s.mistakeLimit !== null && (
        <span className="hud-mistakes" aria-label={`${s.mistakes} mistakes`}>
          {s.mistakes}/{s.mistakeLimit}
        </span>
      )}
    </div>
  );
}
