import { useEffect, useRef, useState } from 'react';
import { Cell } from './Cell';
import { useStore, useGameState, useGameActions } from '../../state/store';
import { bus } from '../../lib/bus';
import type { Coord, CellMarkInput } from '../../engine';
import './board.css';

const LONG_PRESS_MS = (() => {
  try { return Number(localStorage.getItem('bilko_etch_longpress_ms_v1')) || 350; } catch { return 350; }
})();

// Resolve the cell coord from any element in the event's hit path.
// Module-scope so it's not recreated on every render.
function coordFromElement(el: Element | null, cols: number): Coord | null {
  const cell = el?.closest('[data-cell-idx]');
  if (!cell) return null;
  const idx = Number(cell.getAttribute('data-cell-idx'));
  if (isNaN(idx)) return null;
  return { row: Math.floor(idx / cols), col: idx % cols };
}

export function Board() {
  const { board, primary, hover } = useGameState();
  const actions = useGameActions();
  const boardRef = useRef<HTMLDivElement>(null);
  const [focus, setFocus] = useState<Coord>({ row: 0, col: 0 });

  // Keep primary in a ref so long-press timer closure sees the latest value.
  const primaryRef = useRef(primary);
  primaryRef.current = primary;

  // Drag / long-press state in refs — no re-render on every pointermove.
  const dragKind = useRef<CellMarkInput | null>(null);
  const dragPath = useRef<Coord[]>([]);
  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const longPressFired = useRef(false);

  // Programmatically move DOM focus when keyboard cursor changes.
  useEffect(() => {
    const idx = focus.row * board.cols + focus.col;
    const el = boardRef.current?.querySelector<HTMLElement>(`[data-cell-idx="${idx}"]`);
    if (el && document.activeElement !== el) el.focus({ preventScroll: true });
  }, [focus.row, focus.col, board.cols]);

  // Global keyboard handler — window-level so it fires regardless of which cell has focus.
  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      const t = e.target as HTMLElement;
      if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA')) return;

      if (e.key.startsWith('Arrow')) {
        e.preventDefault();
        const dr = e.key === 'ArrowUp' ? -1 : e.key === 'ArrowDown' ? 1 : 0;
        const dc = e.key === 'ArrowLeft' ? -1 : e.key === 'ArrowRight' ? 1 : 0;
        setFocus(f => ({
          row: (f.row + dr + board.rows) % board.rows,
          col: (f.col + dc + board.cols) % board.cols,
        }));
        return;
      }

      const f = focus;
      if (e.key === ' ') { e.preventDefault(); bus.emit('cellMarked', { ...f, kind: 'fill' }); return; }
      if (e.key === 'x' || e.key === 'X') { e.preventDefault(); bus.emit('cellMarked', { ...f, kind: 'cross' }); return; }
      if (e.key === 'Backspace' || e.key === 'Delete') { e.preventDefault(); bus.emit('cellMarked', { ...f, kind: 'clear' }); return; }
      if ((e.key === 'z' || e.key === 'Z') && !e.shiftKey) { e.preventDefault(); actions.undo(); return; }
      if ((e.key === 'y' || e.key === 'Y') || ((e.key === 'z' || e.key === 'Z') && e.shiftKey)) { e.preventDefault(); actions.redo(); return; }
      if (e.key === 'h' || e.key === 'H') { e.preventDefault(); bus.emit('hintRequested', { level: 1 }); return; }
      if (e.key === 'r' || e.key === 'R') { e.preventDefault(); if (confirm('Restart this puzzle?')) actions.restart(); return; }
      if (e.key === 'm' || e.key === 'M') { e.preventDefault(); actions.togglePrimary(); return; }
    }
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [focus, board.rows, board.cols, actions]);

  // ---- Board-level pointer delegation ----------------------------------------
  // setPointerCapture is on the BOARD ROOT so all subsequent pointer events during
  // a drag stay on this element. elementFromPoint then resolves the actual cell
  // under the cursor despite the capture, making drag-traversal work correctly.

  function onBoardPointerDown(e: React.PointerEvent) {
    const c = coordFromElement(e.target as Element, board.cols);
    if (!c) return;

    const isRight = e.button === 2;
    const kind: CellMarkInput = isRight ? 'cross' : primaryRef.current;

    longPressFired.current = false;
    if (!isRight) {
      longPressTimer.current = setTimeout(() => {
        longPressFired.current = true;
        const opposite: CellMarkInput = primaryRef.current === 'fill' ? 'cross' : 'fill';
        bus.emit('cellMarked', { ...c, kind: opposite });
      }, LONG_PRESS_MS);
    }

    dragKind.current = kind;
    dragPath.current = [c];
    (e.currentTarget as Element).setPointerCapture(e.pointerId);
    bus.emit('cellDragStart', c);
  }

  function onBoardPointerMove(e: React.PointerEvent) {
    // elementFromPoint resolves the visual cell under the cursor even while captured.
    const el = document.elementFromPoint(e.clientX, e.clientY);
    const c = coordFromElement(el, board.cols);

    // Update hover. During a drag, skip setHover(null) so the last cell stays lit.
    const st = useStore.getState();
    const cur = st.hover;
    if (!dragKind.current || c) {
      if (c?.row !== cur?.row || c?.col !== cur?.col) st.actions.setHover(c);
    }

    if (!dragKind.current || !c) return;

    // Any movement cancels long-press and commits to drag.
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }

    const last = dragPath.current[dragPath.current.length - 1];
    if (!last || last.row !== c.row || last.col !== c.col) {
      dragPath.current.push(c);
    }
  }

  function onBoardPointerUp(e: React.PointerEvent) {
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }

    const el = document.elementFromPoint(e.clientX, e.clientY);
    const upCoord = coordFromElement(el, board.cols) ?? dragPath.current.at(-1) ?? null;
    if (upCoord) bus.emit('cellDragEnd', upCoord);

    if (longPressFired.current) {
      dragKind.current = null; dragPath.current = [];
      return;
    }

    const dk = dragKind.current;
    if (dk === null) { dragPath.current = []; return; }

    if (dragPath.current.length === 1 && upCoord) {
      // Single tap: bus-bridge applies applyMark with toggle semantics.
      bus.emit('cellMarked', { ...upCoord, kind: dk });
    } else if (dragPath.current.length > 1) {
      // Batched drag → one store call = one undo entry.
      useStore.getState().actions.applyDrag(dragPath.current.slice(), dk);
    }
    dragKind.current = null; dragPath.current = [];
  }

  // ---- Render ----------------------------------------------------------------

  const maxW = `min(92vmin, calc(${board.cols} * 36px), 540px)`;

  return (
    <div
      ref={boardRef}
      className="etch-board"
      role="grid"
      aria-label={`Etch puzzle, ${board.cols} by ${board.rows}`}
      aria-rowcount={board.rows}
      aria-colcount={board.cols}
      style={{
        gridTemplateColumns: `repeat(${board.cols}, 1fr)`,
        aspectRatio: `${board.cols} / ${board.rows}`,
        maxWidth: maxW,
        width: '100%',
      }}
      onPointerDown={onBoardPointerDown}
      onPointerMove={onBoardPointerMove}
      onPointerUp={onBoardPointerUp}
      onContextMenu={(e) => e.preventDefault()}
    >
      {Array.from({ length: board.rows }, (_, row) => (
        // display:contents makes row wrappers invisible to the CSS grid while
        // satisfying the ARIA grid > row > gridcell hierarchy required by WCAG
        <div key={row} role="row" aria-rowindex={row + 1} style={{ display: 'contents' }}>
          {Array.from({ length: board.cols }, (_, col) => {
            const i = row * board.cols + col;
            const focused = focus.row === row && focus.col === col;
            const inHoverRow = hover
              ? (hover.row === row && hover.col !== -1) || (hover.col === -1 && hover.row === row)
              : false;
            const inHoverCol = hover
              ? (hover.col === col && hover.row !== -1) || (hover.row === -1 && hover.col === col)
              : false;
            return (
              <Cell
                key={col}
                idx={i}
                row={row}
                col={col}
                cols={board.cols}
                rows={board.rows}
                mark={board.cells[i] ?? 'unmarked'}
                isFocused={focused}
                isPeerRow={inHoverRow && !inHoverCol}
                isPeerCol={inHoverCol && !inHoverRow}
                isPeerHover={inHoverRow && inHoverCol}
                rowClueId={`row-clue-${row}`}
                colClueId={`col-clue-${col}`}
                onFocus={() => setFocus({ row, col })}
              />
            );
          })}
        </div>
      ))}
    </div>
  );
}
