import { useEffect } from 'react';
import { useGameActions } from '../../state/store';
import { getStreak } from '../../state/streak-store';
import { dailyDifficulty, dateToIso, type EtchSize } from '../../engine';

const SIZE_INITIAL: Record<EtchSize, string> = {
  sketch: 'S', beginner: 'B', intermediate: 'I', tall: 'T', expert: 'E',
};

export function CalendarSheet({ onClose }: { onClose: () => void }) {
  const a = useGameActions();
  const streak = getStreak();
  const today = new Date();

  // Build last 90 days, oldest first, ending today
  const days: Array<{ date: Date; iso: string; isCompleted: boolean }> = [];
  for (let i = 89; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(today.getDate() - i);
    const iso = dateToIso(d);
    days.push({ date: d, iso, isCompleted: streak.completed.includes(iso) });
  }

  // Pad to start on Monday
  const firstDay = days[0]!.date;
  const firstDow = (firstDay.getDay() + 6) % 7; // Monday = 0
  const padded: Array<typeof days[0] | null> = [];
  for (let i = 0; i < firstDow; i++) padded.push(null);
  padded.push(...days);

  useEffect(() => {
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') onClose(); }
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [onClose]);

  return (
    <div className="etch-cal-backdrop" role="dialog" aria-modal="true" aria-label="Daily calendar" onClick={onClose}>
      <div className="etch-cal-sheet" onClick={(e) => e.stopPropagation()}>
        <header>
          <h2>Last 90 days</h2>
          <button onClick={onClose} aria-label="Close">×</button>
        </header>
        <div className="etch-cal-grid">
          {['Mo','Tu','We','Th','Fr','Sa','Su'].map(h => (
            <div key={h} className="etch-cal-h">{h}</div>
          ))}
          {padded.map((d, i) =>
            d === null
              ? <div key={`pad-${i}`} className="etch-cal-pad" />
              : (
                <button
                  key={d.iso}
                  className="etch-cal-cell"
                  data-completed={d.isCompleted || undefined}
                  onClick={() => { void a.loadDailyForDate(d.iso); onClose(); }}
                  aria-label={`${d.iso}, ${dailyDifficulty(d.date)}${d.isCompleted ? ', completed' : ''}`}
                >
                  <span className="etch-cal-num">{d.date.getDate()}</span>
                  <span className="etch-cal-diff">{SIZE_INITIAL[dailyDifficulty(d.date)]}</span>
                  {d.isCompleted && <span className="etch-cal-check">✓</span>}
                </button>
              )
          )}
        </div>
      </div>
    </div>
  );
}
