import { useEffect, useState } from 'react';
import { useGameActions, useGameState } from '../../state/store';
import { getStreak } from '../../state/streak-store';
import { dailyDifficulty, dateToIso } from '../../engine';
import { CalendarSheet } from './CalendarSheet';
import { ShareTile } from './ShareTile';
import './daily.css';

export function DailyHero() {
  const a = useGameActions();
  const s = useGameState();
  const [showCal, setShowCal] = useState(false);
  const [showShare, setShowShare] = useState(false);

  const today = new Date();
  const todayIso = dateToIso(today);
  const todayDifficulty = dailyDifficulty(today);
  const dayName = today.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });
  const streak = getStreak();
  const completedToday = streak.completed.includes(todayIso);

  // Auto-load from URL param
  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const d = params.get('d');
    if (d && /^\d{4}-\d{2}-\d{2}$/.test(d)) {
      void a.loadDailyForDate(d);
    }
  }, [a]);

  // Show share on solve
  useEffect(() => {
    if (s.solved && s.mode === 'daily') {
      // Don't auto-show — user can click the share button
    }
  }, [s.solved, s.mode]);

  return (
    <div className="etch-daily-hero" data-slot="daily">
      <div className="etch-daily-info">
        <p className="etch-daily-eyebrow">Daily · {dayName}</p>
        <p className="etch-daily-difficulty">{todayDifficulty}</p>
        {completedToday ? (
          <p className="etch-daily-status">Solved today · streak {streak.current} 🔥</p>
        ) : (
          <button
            className="etch-daily-play"
            onClick={() => void a.newGame({ mode: 'daily' })}
            aria-label="Play today's daily puzzle"
          >
            Play today
          </button>
        )}
      </div>
      <div className="etch-daily-actions">
        {(completedToday || (s.solved && s.mode === 'daily')) && (
          <button
            className="etch-daily-icon"
            onClick={() => setShowShare(true)}
            aria-label="Share result"
          >
            ↗
          </button>
        )}
        <button
          className="etch-daily-icon"
          onClick={() => setShowCal(true)}
          aria-label="Open calendar"
        >
          📅
        </button>
      </div>
      {showCal && <CalendarSheet onClose={() => setShowCal(false)} />}
      {showShare && <ShareTile onClose={() => setShowShare(false)} />}
    </div>
  );
}
