import type { EtchSize } from '../../engine';

const SIZES: { key: EtchSize; name: string; dims: string; target: string }[] = [
  { key: 'sketch',       name: 'Sketch',       dims: '5 × 5',   target: '~90 s' },
  { key: 'beginner',     name: 'Beginner',     dims: '10 × 10', target: '~4 min' },
  { key: 'intermediate', name: 'Intermediate', dims: '15 × 15', target: '~10 min' },
  { key: 'tall',         name: 'Tall',         dims: '15 × 20', target: '~14 min' },
  { key: 'expert',       name: 'Expert',       dims: '20 × 20', target: '~25 min' },
];

export function SizeGrid({ size, onChange }: { size: EtchSize; onChange: (s: EtchSize) => void }) {
  return (
    <div className="etch-size-grid" role="radiogroup" aria-label="Puzzle size">
      {SIZES.map(s => (
        <button
          key={s.key}
          role="radio"
          aria-checked={s.key === size}
          aria-pressed={s.key === size}
          className="etch-size-card"
          data-active={s.key === size ? '' : undefined}
          onClick={() => onChange(s.key)}
        >
          <div className="etch-size-name">{s.name}</div>
          <div className="etch-size-dims">{s.dims}</div>
          <div className="etch-size-target">{s.target}</div>
          <div className="etch-size-badge">🧠 No-guess</div>
        </button>
      ))}
    </div>
  );
}
