import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import { initBusBridge } from './state/bus-bridge';
import { initHintBridge } from './components/hints';
import { useStore } from './state/store';
import { getMistakeMode } from './features/theme/theme';

initBusBridge();
initHintBridge();

// Restore persisted game (resume from localStorage)
useStore.getState().actions.resume();

// Apply persisted mistake mode on boot
const mm = getMistakeMode();
useStore.setState({ mistakeLimit: mm === 'off' ? null : Number(mm) });

// Expose store for Playwright tests in dev mode
if (import.meta.env.DEV) (window as unknown as Record<string, unknown>).__ETCH_STORE__ = useStore;

createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
);
