import { bus } from '../../lib/bus';
import { useStore } from '../../state/store';
import { useHintStore } from '../../state/hint-state';
import { nextHint } from '../../engine';

let bridged = false;

export function initHintBridge() {
  if (bridged) return;
  bridged = true;

  bus.on('hintRequested', () => {
    const s = useStore.getState();
    if (s.solved || s.revealed || s.paused) return;
    const cur = useHintStore.getState();
    const nextLevel = (cur.level >= 3 ? 1 : cur.level + 1) as 1 | 2 | 3;
    const info = nextHint(s.board);
    if (!info) {
      useHintStore.getState().setLevel(0, null);
      return;
    }
    useHintStore.getState().setLevel(nextLevel, info);
    // Highlight the line via the store's hover — board interprets {row, col:-1} as whole row
    if (info.line.kind === 'row') s.actions.setHover({ row: info.line.index, col: -1 });
    else s.actions.setHover({ row: -1, col: info.line.index });
    if (nextLevel === 3) s.actions.noteHintUsed();
  });

  bus.on('cellMarked', () => {
    const cur = useHintStore.getState();
    if (cur.level !== 0) {
      cur.reset();
      useStore.getState().actions.setHover(null);
      document.querySelectorAll('[data-hint-highlight]').forEach(
        el => el.removeAttribute('data-hint-highlight')
      );
    }
  });
}

export { HintBanner } from './HintBanner';
