import { useEffect } from 'react';

export function RevealOverlay() {
  useEffect(() => {
    const board = document.querySelector('.etch-board');
    if (!board) return;
    board.setAttribute('data-revealing', 'true');
    board.setAttribute('data-win-pulse', 'true');
    const t = setTimeout(() => {
      board.removeAttribute('data-revealing');
      board.removeAttribute('data-win-pulse');
    }, 940);
    return () => {
      clearTimeout(t);
      board.removeAttribute('data-revealing');
      board.removeAttribute('data-win-pulse');
    };
  }, []);

  return null;
}
