import { useEffect, useState } from 'react';
import { bus } from '../lib/bus';
import { Confetti } from '../features/anim/Confetti';
import { RevealOverlay } from '../features/anim/RevealOverlay';
import { initAnim } from '../features/anim';
import { initFeedback } from '../features/feedback';
import { mountFeedbackSettings } from '../features/feedback/settings-mount';
import '../features/anim/anim.css';

// Init side-effects at module level (stable across renders)
initAnim();
initFeedback();
mountFeedbackSettings();

export function AnimationsSlot() {
  const [revealing, setRevealing] = useState(false);
  const [winningPB, setWinningPB] = useState(false);

  useEffect(() => {
    const off = bus.on('puzzleSolved', ({ isPersonalBest }) => {
      setRevealing(true);
      setTimeout(() => setRevealing(false), 940);
      if (isPersonalBest) {
        setTimeout(() => setWinningPB(true), 940);
      }
    });
    return off;
  }, []);

  return (
    <>
      {revealing && <RevealOverlay />}
      {winningPB && <Confetti onDone={() => setWinningPB(false)} />}
    </>
  );
}
